/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = ("<div class=\"home-container\">\n    <!-- Hero Section -->\n    <section class=\"hero\">\n        <div class=\"hero-content\">\n            <div class=\"hero-header\">\n                <div class=\"hero-logo\">\n                    <img src=\"assets/images/dooboostore.png\" alt=\"dooboostore\" class=\"hero-logo-img\">\n                </div>\n                <h1 class=\"hero-title content en\">Integrated Development Platform</h1>\n                <h1 class=\"hero-title content ko\">통합 개발 플랫폼</h1>\n            </div>\n\n            <p class=\"hero-subtitle content en\">\n                dooboostore provides a comprehensive ecosystem of tools and utilities to build\n                <strong>high-quality applications</strong> from frontend to backend with powerful features and clean\n                architecture.\n            </p>\n            <p class=\"hero-subtitle content ko\">\n                dooboostore는 강력한 기능과 깔끔한 아키텍처로 프론트엔드부터 백엔드까지\n                <strong>고품질 애플리케이션</strong>을 구축할 수 있는 포괄적인 도구와 유틸리티 생태계를 제공합니다.\n            </p>\n\n            <div class=\"hero-actions\">\n                <dr-a href=\"/packages\" class=\"btn-get-started content en\">Get Started</dr-a>\n                <dr-a href=\"/packages\" class=\"btn-get-started content ko\">시작 하기</dr-a>\n            </div>\n\n            <div class=\"hero-badges\">\n                <a href=\"https://github.com/dooboostore-develop\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Github-555555?style=flat&logo=github&logoColor=white\" alt=\"GitHub\"/>\n                </a>\n                <a href=\"https://www.npmjs.com/~dooboostore\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Npm-cc0000?style=flat&logo=npm&logoColor=white\" alt=\"NPM\"/>\n                </a>\n                <a href=\"https://www.typescriptlang.org/\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Typescript-3178C6?style=flat&logo=typescript&logoColor=white\" alt=\"TypeScript\"/>\n                </a>\n                <img alt=\"Hits\" src=\"https://hits.sh/hits.sh/dooboostore-develop.github.io.svg?style=plastic&extraCount=426612\"/>\n            </div>\n        </div>\n    </section>\n\n    <!-- What's in dooboostore -->\n    <section class=\"whats-in\">\n        <div class=\"container\">\n            <div class=\"section-header\">\n                <h2 class=\"content en\">What's in dooboostore?</h2>\n                <p class=\"content en\">Everything you need to build great applications.</p>\n\n                <h2 class=\"content ko\">dooboostore에는 무엇이 있나요?</h2>\n                <p class=\"content ko\">훌륭한 애플리케이션을 만들기 위해 필요한 모든 것.</p>\n            </div>\n\n            <div class=\"features-grid\">\n                <div class=\"feature-card\">\n                    <div class=\"feature-visual\">\n                        <div class=\"feature-icon\">🚀</div>\n                    </div>\n                    <h3 class=\"content en\">Dependency Injection</h3>\n                    <p class=\"content en\">Powerful DI container with AOP support for clean, maintainable code\n                        architecture.</p>\n\n                    <h3 class=\"content ko\">의존성 주입</h3>\n                    <p class=\"content ko\">깔끔하고 유지보수 가능한 코드 아키텍처를 위한 AOP 지원 강력한 DI 컨테이너.</p>\n                </div>\n\n                <div class=\"feature-card\">\n                    <div class=\"feature-visual\">\n                        <div class=\"feature-icon\">⚡</div>\n                    </div>\n                    <h3 class=\"content en\">Rich Utilities</h3>\n                    <p class=\"content en\">Comprehensive utility library with array, object, string, date manipulation\n                        and more.</p>\n\n                    <h3 class=\"content ko\">풍부한 유틸리티</h3>\n                    <p class=\"content ko\">배열, 객체, 문자열, 날짜 조작 등을 포함한 포괄적인 유틸리티 라이브러리.</p>\n                </div>\n\n                <div class=\"feature-card\">\n                    <div class=\"feature-visual\">\n                        <div class=\"feature-icon\">🔧</div>\n                    </div>\n                    <h3 class=\"content en\">DOM Rendering</h3>\n                    <p class=\"content en\">Lightweight DOM rendering engine with reactive data binding and component\n                        lifecycle.</p>\n\n                    <h3 class=\"content ko\">DOM 렌더링</h3>\n                    <p class=\"content ko\">반응형 데이터 바인딩과 컴포넌트 생명주기를 가진 경량 DOM 렌더링 엔진.</p>\n                </div>\n\n                <div class=\"feature-card\">\n                    <div class=\"feature-visual\">\n                        <div class=\"feature-icon\">📦</div>\n                    </div>\n                    <h3 class=\"content en\">HTTP Server</h3>\n                    <p class=\"content en\">Build robust HTTP servers with decorative routing, middleware, and session\n                        management.</p>\n\n                    <h3 class=\"content ko\">HTTP 서버</h3>\n                    <p class=\"content ko\">데코레이터 라우팅, 미들웨어, 세션 관리로 견고한 HTTP 서버를 구축하세요.</p>\n                </div>\n\n                <div class=\"feature-card\">\n                    <div class=\"feature-visual\">\n                        <div class=\"feature-icon\">🎨</div>\n                    </div>\n                    <h3 class=\"content en\">Observable System</h3>\n                    <p class=\"content en\">RxJS-like reactive programming with operators for handling asynchronous data\n                        streams.</p>\n\n                    <h3 class=\"content ko\">Observable 시스템</h3>\n                    <p class=\"content ko\">비동기 데이터 스트림 처리를 위한 연산자가 있는 RxJS와 같은 반응형 프로그래밍.</p>\n                </div>\n\n                <div class=\"feature-card\">\n                    <div class=\"feature-visual\">\n                        <div class=\"feature-icon\">🔄</div>\n                    </div>\n                    <h3 class=\"content en\">Frontend Framework</h3>\n                    <p class=\"content en\">Single Page Application framework with component-based architecture and\n                        routing.</p>\n\n                    <h3 class=\"content ko\">프론트엔드 프레임워크</h3>\n                    <p class=\"content ko\">컴포넌트 기반 아키텍처와 라우팅을 가진 단일 페이지 애플리케이션 프레임워크.</p>\n                </div>\n\n                <div class=\"feature-card\">\n                    <div class=\"feature-visual\">\n                        <div class=\"feature-icon\">🛠️</div>\n                    </div>\n                    <h3 class=\"content en\">Type Safety</h3>\n                    <p class=\"content en\">Built with TypeScript-first approach providing comprehensive type definitions\n                        and safety.</p>\n\n                    <h3 class=\"content ko\">타입 안전성</h3>\n                    <p class=\"content ko\">포괄적인 타입 정의와 안전성을 제공하는 TypeScript 우선 접근 방식으로 구축.</p>\n                </div>\n\n                <div class=\"feature-card\">\n                    <div class=\"feature-visual\">\n                        <div class=\"feature-icon\">⚙️</div>\n                    </div>\n                    <h3 class=\"content en\">Modular Architecture</h3>\n                    <p class=\"content en\">Pick and choose only the packages you need with a fully modular ecosystem\n                        design.</p>\n\n                    <h3 class=\"content ko\">모듈형 아키텍처</h3>\n                    <p class=\"content ko\">완전히 모듈화된 생태계 설계로 필요한 패키지만 선택해서 사용하세요.</p>\n                </div>\n\n                <div class=\"feature-card\">\n                    <div class=\"feature-visual\">\n                        <div style=\"background-color: rgba(255, 255, 255, 1); width: 64px; height: 64px; border-radius: 12px; display: flex; align-items: center; justify-content: center;\">\n                            <img src=\"https://raw.githubusercontent.com/dooboostore-develop/swt/HEAD/document/assets/logo.png\" alt=\"SWT Logo\" style=\"width: 48px; height: 48px;\">\n                        </div>\n                    </div>\n                    <h3 class=\"content en\">User Tracking (SWT)</h3>\n                    <p class=\"content en\">Lightweight user tracking with <strong>S</strong>imple <strong>W</strong>eb <strong>T</strong>racker (SWT). Analyze user behavior with session replays, heatmaps, and a built-in dashboard.</p>\n\n                    <h3 class=\"content ko\">사용자 추적 (SWT)</h3>\n                    <p class=\"content ko\">경량 사용자 추적 라이브러리 <strong>S</strong>imple <strong>W</strong>eb <strong>T</strong>racker (SWT). 세션 리플레이, 히트맵, 내장 대시보드로 사용자 행동을 분석하세요.</p>\n                </div>\n            </div>\n        </div>\n    </section>\n\n    <!-- Testimonials -->\n    <section class=\"testimonials\">\n        <div class=\"container\">\n            <div class=\"testimonials-header\">\n                <p class=\"testimonials-intro content en\">\n                    For <strong>performance</strong>, <strong>efficiency</strong> and <strong>developer\n                    experience</strong>.\n                </p>\n                <p class=\"testimonials-subtitle content en\">\n                    dooboostore is trusted by developers and companies worldwide.\n                </p>\n                <p class=\"testimonials-intro content ko\">\n                    <strong>성능</strong>, <strong>효율성</strong> 그리고 <strong>개발자 경험</strong>을 위해.\n                </p>\n                <p class=\"testimonials-subtitle content ko\">\n                    dooboostore는 전 세계 개발자와 기업들의 신뢰를 받고 있습니다.\n                </p>\n            </div>\n\n            <div class=\"testimonials-grid\">\n                <div class=\"testimonial-card\">\n                    <p class=\"testimonial-text content en\">\n                        \"dooboostore's DI system and modular architecture have transformed our development workflow. We\n                        can now build scalable applications with clean, maintainable code.\"\n                    </p>\n                    <div class=\"testimonial-author content en\">\n                        <div class=\"author-logo\">D</div>\n                        <div class=\"author-info\">\n                            <div class=\"author-name\">Developer Team</div>\n                            <div class=\"author-title\">Senior Software Engineer, Frontend</div>\n                        </div>\n                    </div>\n\n                    <p class=\"testimonial-text content ko\">\n                        \"dooboostore의 DI 시스템과 모듈형 아키텍처가 우리의 개발 워크플로우를 완전히 바꿔놓았습니다. 이제 깔끔하고 유지보수 가능한 코드로 확장 가능한 애플리케이션을\n                        구축할 수 있습니다.\"\n                    </p>\n                    <div class=\"testimonial-author content ko\">\n                        <div class=\"author-logo\">개</div>\n                        <div class=\"author-info\">\n                            <div class=\"author-name\">개발팀</div>\n                            <div class=\"author-title\">시니어 소프트웨어 엔지니어, 프론트엔드</div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"testimonial-card\">\n                    <p class=\"testimonial-text content en\">\n                        \"The reactive data binding and component lifecycle in dooboostore's DOM rendering engine\n                        provides excellent performance with minimal overhead.\"\n                    </p>\n                    <div class=\"testimonial-author content en\">\n                        <div class=\"author-logo\">T</div>\n                        <div class=\"author-info\">\n                            <div class=\"author-name\">Tech Startup</div>\n                            <div class=\"author-title\">CTO, Product Engineering</div>\n                        </div>\n                    </div>\n\n                    <p class=\"testimonial-text content ko\">\n                        \"dooboostore의 DOM 렌더링 엔진의 반응형 데이터 바인딩과 컴포넌트 생명주기는 최소한의 오버헤드로 뛰어난 성능을 제공합니다.\"\n                    </p>\n                    <div class=\"testimonial-author content ko\">\n                        <div class=\"author-logo\">기</div>\n                        <div class=\"author-info\">\n                            <div class=\"author-name\">기술 스타트업</div>\n                            <div class=\"author-title\">CTO, 제품 엔지니어링</div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"testimonial-card\">\n                    <p class=\"testimonial-text content en\">\n                        \"Building HTTP servers with dooboostore's decorative routing and middleware system has never\n                        been easier. The TypeScript integration is seamless.\"\n                    </p>\n                    <div class=\"testimonial-author content en\">\n                        <div class=\"author-logo\">E</div>\n                        <div class=\"author-info\">\n                            <div class=\"author-name\">Enterprise Corp</div>\n                            <div class=\"author-title\">Lead Developer, Backend Team</div>\n                        </div>\n                    </div>\n\n                    <p class=\"testimonial-text content ko\">\n                        \"dooboostore의 데코레이터 라우팅과 미들웨어 시스템으로 HTTP 서버를 구축하는 것이 이렇게 쉬울 줄 몰랐습니다. TypeScript 통합이 완벽합니다.\"\n                    </p>\n                    <div class=\"testimonial-author content ko\">\n                        <div class=\"author-logo\">기</div>\n                        <div class=\"author-info\">\n                            <div class=\"author-name\">기업</div>\n                            <div class=\"author-title\">리드 개발자, 백엔드 팀</div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </section>\n</div>");

