/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = ("<div class=\"package-container\">\n    <div class=\"package-header\">\n        <div class=\"container\">\n            <h1>core-node</h1>\n            <p class=\"content en\">Node.js utilities and file system operations</p>\n            <p class=\"content ko\">Node.js 유틸리티 및 파일 시스템 작업</p>\n            <div class=\"package-actions\">\n                <a href=\"https://github.com/dooboostore-develop/packages\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Github-555555?style=flat&logo=github&logoColor=white\" alt=\"GitHub\"/>\n                </a>\n                <a href=\"https://www.npmjs.com/package/@dooboostore/core-node\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Npm-cc0000?style=flat&logo=npm&logoColor=white\" alt=\"NPM\"/>\n                </a>\n            </div>\n        </div>\n    </div>\n    <div class=\"package-content\">\n        <div class=\"container\">\n            <!-- Installation -->\n            <section class=\"section\">\n                <h2 id=\"installation\">Installation</h2>\n                <p class=\"content en\">Install the package and its peer dependency:</p>\n                <p class=\"content ko\">패키지와 필수 의존성을 설치하세요:</p>\n                \n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">npm</span>\n                    </div>\n                    <pre><code class=\"language-bash\">npm install @dooboostore/core-node @dooboostore/core</code></pre>\n                </div>\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">pnpm</span>\n                    </div>\n                    <pre><code class=\"language-bash\">pnpm add @dooboostore/core-node @dooboostore/core</code></pre>\n                </div>\n            </section>\n\n            <!-- Features -->\n            <section class=\"section\">\n                <h2 id=\"features\">Features</h2>\n                <div class=\"features-grid\">\n                    <div class=\"feature-item\">\n                        <h3>File System Operations</h3>\n                        <p class=\"content en\">Comprehensive file operations with File class and utility functions</p>\n                        <p class=\"content ko\">File 클래스와 유틸리티 함수를 통한 포괄적인 파일 작업</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Buffer Conversion</h3>\n                        <p class=\"content en\">Advanced buffer handling with Base64 support and encoding options</p>\n                        <p class=\"content ko\">Base64 지원과 인코딩 옵션을 포함한 고급 버퍼 처리</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Path Management</h3>\n                        <p class=\"content en\">Cross-platform path utilities for file and directory operations</p>\n                        <p class=\"content ko\">파일 및 디렉토리 작업을 위한 크로스 플랫폼 경로 유틸리티</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Memory Utilities</h3>\n                        <p class=\"content en\">Memory management and monitoring utilities for Node.js applications</p>\n                        <p class=\"content ko\">Node.js 애플리케이션을 위한 메모리 관리 및 모니터링 유틸리티</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Process Management</h3>\n                        <p class=\"content en\">Process lifecycle management and event handling utilities</p>\n                        <p class=\"content ko\">프로세스 생명주기 관리 및 이벤트 처리 유틸리티</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Node.js Optimized</h3>\n                        <p class=\"content en\">Specifically designed for Node.js runtime environment</p>\n                        <p class=\"content ko\">Node.js 런타임 환경에 특별히 설계됨</p>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Quick Start -->\n            <section class=\"section\">\n                <h2 id=\"quick-start\">Quick Start</h2>\n                \n                <h3 id=\"file-operations\">File Operations</h3>\n                <p class=\"content en\">Handle file operations with the File class:</p>\n                <p class=\"content ko\">File 클래스로 파일 작업을 처리하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; FileUtils &#125; from '@dooboostore/core-node/file/FileUtils';\nimport &#123; ConvertUtils &#125; from '@dooboostore/core-node/convert/ConvertUtils';\n\nasync function handleFileUpload(base64Data: string) &#123;\n  // Convert Base64 string to Buffer\n  const imageBuffer = ConvertUtils.toBuffer(base64Data, &#123; encoding: 'base64' &#125;);\n\n  // Write buffer to a temporary file\n  const tempFile = await FileUtils.writeFile(imageBuffer, &#123;\n    originalName: 'my-image.png'\n  &#125;);\n\n  console.log(`File created at: $&#123;tempFile.path&#125;`);\n  console.log(`File size: $&#123;tempFile.size&#125; bytes`);\n\n  // Move file to permanent location\n  const permanentPath = `./uploads/$&#123;tempFile.fileName&#125;`;\n  await tempFile.move(permanentPath);\n\n  console.log(`File moved to: $&#123;tempFile.path&#125;`);\n&#125;</code></pre>\n                </div>\n\n                <h3 id=\"buffer-conversion\">Buffer Conversion</h3>\n                <p class=\"content en\">Convert strings to buffers with various encoding options:</p>\n                <p class=\"content ko\">다양한 인코딩 옵션으로 문자열을 버퍼로 변환하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; ConvertUtils &#125; from '@dooboostore/core-node/convert/ConvertUtils';\n\n// Convert Base64 data URL to Buffer\nconst base64Data = 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=';\nconst buffer = ConvertUtils.toBuffer(base64Data, &#123; encoding: 'base64' &#125;);\n\n// Convert regular string to Buffer\nconst textBuffer = ConvertUtils.toBuffer('Hello World');\n\n// Convert Buffer back to string\nconst text = ConvertUtils.toString(buffer, &#123; encoding: 'utf-8' &#125;);</code></pre>\n                </div>\n\n                <h3 id=\"file-utilities\">File System Utilities</h3>\n                <p class=\"content en\">Use comprehensive file system utilities:</p>\n                <p class=\"content ko\">포괄적인 파일 시스템 유틸리티를 사용하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; FileUtils &#125; from '@dooboostore/core-node/file/FileUtils';\n\n// Check if file exists\nconst exists = FileUtils.existesSync('./myfile.txt', &#123;\n  existes: (path) =&gt; console.log(`File exists: $&#123;path&#125;`),\n  noExistes: (path) =&gt; console.log(`File not found: $&#123;path&#125;`)\n&#125;);\n\n// Create directory\nawait FileUtils.mkdir('./uploads', &#123; recursive: true &#125;);\n\n// Read file\nconst content = FileUtils.readSync('./myfile.txt');\n\n// Write file\nFileUtils.write('Hello World', &#123; path: './output.txt' &#125;);\n\n// Append to file\nFileUtils.writeAppend('\\\\nNew line', &#123; path: './output.txt' &#125;);\n\n// Delete file\nFileUtils.deleteFileSync('./temp.txt');</code></pre>\n                </div>\n            </section>\n\n            <!-- Advanced Features -->\n            <section class=\"section\">\n                <h2 id=\"advanced-features\">Advanced Features</h2>\n                \n                <h3 id=\"file-class\">File Class Methods</h3>\n                <p class=\"content en\">Use the File class for object-oriented file operations:</p>\n                <p class=\"content ko\">객체 지향 파일 작업을 위해 File 클래스를 사용하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; FileUtils &#125; from '@dooboostore/core-node/file/FileUtils';\n\n// Create a File instance\nconst file = new FileUtils.File(&#123; \n  path: './documents/report.pdf',\n  originalName: 'monthly-report.pdf'\n&#125;);\n\n// Get file information\nconsole.log('File name:', file.fileName);\nconsole.log('Directory:', file.directory);\nconsole.log('Extension:', file.extension);\nconsole.log('Original name:', file.originalName);\nconsole.log('File size:', file.size);\n\n// Copy file\nawait file.copy('./backup/report-copy.pdf');\n\n// Rename file\nawait file.rename('annual-report.pdf');\n\n// Move file to different directory\nawait file.move('./archive/reports/annual-report.pdf');\n\n// Delete file\nawait file.delete();</code></pre>\n                </div>\n\n                <h3 id=\"path-utilities\">Path Utilities</h3>\n                <p class=\"content en\">Handle cross-platform path operations:</p>\n                <p class=\"content ko\">크로스 플랫폼 경로 작업을 처리하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; FileUtils &#125; from '@dooboostore/core-node/file/FileUtils';\n\n// Join path segments\nconst fullPath = FileUtils.path(['documents', 'images', 'photo.jpg']);\n// Result: 'documents/images/photo.jpg' (Unix) or 'documents\\\\images\\\\photo.jpg' (Windows)\n\n// Array of path segments\nconst pathSegments = ['home', 'user', 'projects', 'myapp'];\nconst projectPath = FileUtils.path(pathSegments);\n\n// Single path string\nconst singlePath = FileUtils.path('./src/components/Button.tsx');</code></pre>\n                </div>\n\n                <h3 id=\"async-operations\">Asynchronous Operations</h3>\n                <p class=\"content en\">Handle asynchronous file operations efficiently:</p>\n                <p class=\"content ko\">비동기 파일 작업을 효율적으로 처리하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; FileUtils &#125; from '@dooboostore/core-node/file/FileUtils';\n\nasync function processFiles() &#123;\n  try &#123;\n    // Create directory asynchronously\n    const dirPath = await FileUtils.mkdir('./temp/processing');\n    \n    // Read file asynchronously\n    const content = await FileUtils.read('./input.txt', &#123; \n      option: &#123; encoding: 'utf-8' &#125; \n    &#125;);\n    \n    // Process content and write to new file\n    const processedContent = content.toString().toUpperCase();\n    const buffer = Buffer.from(processedContent);\n    \n    const outputFile = await FileUtils.writeFile(buffer, &#123;\n      path: './temp/processing/output.txt',\n      originalName: 'processed-input.txt'\n    &#125;);\n    \n    console.log('Processing complete:', outputFile.path);\n    \n  &#125; catch (error) &#123;\n    console.error('File processing error:', error);\n  &#125;\n&#125;</code></pre>\n                </div>\n            </section>\n\n            <!-- API Reference -->\n            <section class=\"section\">\n                <h2 id=\"api-reference\">API Reference</h2>\n                \n                <h3 id=\"fileutils-namespace\">FileUtils Namespace</h3>\n                <div class=\"api-grid\">\n                    <div class=\"api-item\">\n                        <h4>File Class</h4>\n                        <p class=\"content en\">Object-oriented file wrapper with methods for file operations</p>\n                        <p class=\"content ko\">파일 작업을 위한 메서드를 포함한 객체 지향 파일 래퍼</p>\n                        <ul>\n                            <li><code>constructor(data: &#123;path: string, originalName?: string&#125;)</code></li>\n                            <li><code>copy(newPath: string): Promise&lt;void&gt;</code></li>\n                            <li><code>move(newPath: string): Promise&lt;void&gt;</code></li>\n                            <li><code>rename(newName: string): Promise&lt;void&gt;</code></li>\n                            <li><code>delete(): Promise&lt;void&gt;</code></li>\n                            <li><code>updateStats(): Promise&lt;void&gt;</code></li>\n                        </ul>\n                    </div>\n                    <div class=\"api-item\">\n                        <h4>Utility Functions</h4>\n                        <p class=\"content en\">Static utility functions for common file operations</p>\n                        <p class=\"content ko\">일반적인 파일 작업을 위한 정적 유틸리티 함수</p>\n                        <ul>\n                            <li><code>writeFile(buffer: Buffer, config): Promise&lt;File&gt;</code></li>\n                            <li><code>existesSync(path: PathParamType): boolean</code></li>\n                            <li><code>mkdir(path: PathParamType): Promise&lt;string&gt;</code></li>\n                            <li><code>readSync(path: PathParamType): Buffer</code></li>\n                            <li><code>write(data: string | Buffer, config): string</code></li>\n                            <li><code>deleteSync(path: PathParamType): void</code></li>\n                        </ul>\n                    </div>\n                </div>\n\n                <h3 id=\"convertutils-namespace\">ConvertUtils Namespace</h3>\n                <div class=\"api-grid\">\n                    <div class=\"api-item\">\n                        <h4>String Conversion</h4>\n                        <p class=\"content en\">Convert between strings and buffers with encoding support</p>\n                        <p class=\"content ko\">인코딩 지원으로 문자열과 버퍼 간 변환</p>\n                        <ul>\n                            <li><code>toString(data: string | Buffer, config?): string</code></li>\n                            <li><code>toBuffer(data: string, config?): Buffer</code></li>\n                        </ul>\n                    </div>\n                    <div class=\"api-item\">\n                        <h4>Encoding Options</h4>\n                        <p class=\"content en\">Support for various buffer encodings including Base64</p>\n                        <p class=\"content ko\">Base64를 포함한 다양한 버퍼 인코딩 지원</p>\n                        <ul>\n                            <li><code>encoding: BufferEncoding</code> - utf-8, base64, hex, etc.</li>\n                            <li>Automatic Base64 data URL prefix removal</li>\n                        </ul>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Core Concepts -->\n            <section class=\"section\">\n                <h2 id=\"core-concepts\">Core Concepts</h2>\n                <div class=\"concepts-grid\">\n                    <div class=\"concept-item\">\n                        <h4>File Class</h4>\n                        <p class=\"content en\">Object-oriented wrapper around file paths with built-in operations</p>\n                        <p class=\"content ko\">내장 작업을 포함한 파일 경로의 객체 지향 래퍼</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Buffer Management</h4>\n                        <p class=\"content en\">Efficient handling of binary data with encoding support</p>\n                        <p class=\"content ko\">인코딩 지원을 통한 효율적인 바이너리 데이터 처리</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Path Utilities</h4>\n                        <p class=\"content en\">Cross-platform path handling with array and string support</p>\n                        <p class=\"content ko\">배열과 문자열 지원을 통한 크로스 플랫폼 경로 처리</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Async/Sync Operations</h4>\n                        <p class=\"content en\">Both synchronous and asynchronous file operation methods</p>\n                        <p class=\"content ko\">동기 및 비동기 파일 작업 메서드 모두 지원</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Error Handling</h4>\n                        <p class=\"content en\">Graceful error handling with optional callback functions</p>\n                        <p class=\"content ko\">선택적 콜백 함수를 통한 우아한 오류 처리</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Node.js Integration</h4>\n                        <p class=\"content en\">Deep integration with Node.js file system and process APIs</p>\n                        <p class=\"content ko\">Node.js 파일 시스템 및 프로세스 API와의 깊은 통합</p>\n                    </div>\n                </div>\n            </section>\n        </div>\n    </div>\n</div>");

