/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = ("<div class=\"package-container\">\n    <div class=\"package-header\">\n        <div class=\"container\">\n            <h1>core-web</h1>\n            <p class=\"content en\">Web browser utilities and DOM manipulation tools</p>\n            <p class=\"content ko\">웹 브라우저 유틸리티 및 DOM 조작 도구</p>\n            <div class=\"package-actions\">\n                <a href=\"https://github.com/dooboostore-develop/packages\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Github-555555?style=flat&logo=github&logoColor=white\" alt=\"GitHub\"/>\n                </a>\n                <a href=\"https://www.npmjs.com/package/@dooboostore/core-web\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Npm-cc0000?style=flat&logo=npm&logoColor=white\" alt=\"NPM\"/>\n                </a>\n            </div>\n        </div>\n    </div>\n    <div class=\"package-content\">\n        <div class=\"container\">\n            <!-- Installation -->\n            <section class=\"section\">\n                <h2 id=\"installation\">Installation</h2>\n                <p class=\"content en\">Install the package and its peer dependency:</p>\n                <p class=\"content ko\">패키지와 필수 의존성을 설치하세요:</p>\n                \n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">npm</span>\n                    </div>\n                    <pre><code class=\"language-bash\">npm install @dooboostore/core-web @dooboostore/core</code></pre>\n                </div>\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">pnpm</span>\n                    </div>\n                    <pre><code class=\"language-bash\">pnpm add @dooboostore/core-web @dooboostore/core</code></pre>\n                </div>\n            </section>\n\n            <!-- Features -->\n            <section class=\"section\">\n                <h2 id=\"features\">Features</h2>\n                <div class=\"features-grid\">\n                    <div class=\"feature-item\">\n                        <h3>DOM Manipulation</h3>\n                        <p class=\"content en\">Comprehensive utilities for querying DOM, manipulating nodes, and managing attributes</p>\n                        <p class=\"content ko\">DOM 쿼리, 노드 조작, 속성 관리를 위한 포괄적인 유틸리티</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Browser APIs</h3>\n                        <p class=\"content en\">Easy-to-use wrappers for Clipboard, Storage, and Cookie APIs</p>\n                        <p class=\"content ko\">클립보드, 스토리지, 쿠키 API를 위한 사용하기 쉬운 래퍼</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Resource Loading</h3>\n                        <p class=\"content en\">Asynchronous loading of images, audio, scripts, and stylesheets</p>\n                        <p class=\"content ko\">이미지, 오디오, 스크립트, 스타일시트의 비동기 로딩</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Event Handling</h3>\n                        <p class=\"content en\">Observable streams from DOM and window events</p>\n                        <p class=\"content ko\">DOM 및 윈도우 이벤트로부터 Observable 스트림 생성</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Animation Utilities</h3>\n                        <p class=\"content en\">Tools for requestAnimationFrame and FPS monitoring</p>\n                        <p class=\"content ko\">requestAnimationFrame과 FPS 모니터링을 위한 도구</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Image Processing</h3>\n                        <p class=\"content en\">Advanced converters for File, Blob, Canvas, and Base64 data</p>\n                        <p class=\"content ko\">File, Blob, Canvas, Base64 데이터를 위한 고급 변환기</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Environment Detection</h3>\n                        <p class=\"content en\">Browser environment and mobile webview detection</p>\n                        <p class=\"content ko\">브라우저 환경 및 모바일 웹뷰 감지</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Web Validation</h3>\n                        <p class=\"content en\">Browser-specific validation and environment checks</p>\n                        <p class=\"content ko\">브라우저별 검증 및 환경 체크</p>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Quick Start -->\n            <section class=\"section\">\n                <h2 id=\"quick-start\">Quick Start</h2>\n                \n                <h3 id=\"storage-operations\">Storage Operations</h3>\n                <p class=\"content en\">Handle localStorage and sessionStorage with ease:</p>\n                <p class=\"content ko\">localStorage와 sessionStorage를 쉽게 처리하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; StorageUtils &#125; from '@dooboostore/core-web/storage/StorageUtils';\n\n// Save an object to localStorage\nconst user = &#123; id: 1, name: 'John Doe' &#125;;\nStorageUtils.setLocalStorageItem('currentUser', user, window);\n\n// Retrieve and parse the object\nconst savedUser = StorageUtils.getLocalStorageJsonItem&lt;&#123; id: number, name: string &#125;&gt;('currentUser', window);\nconsole.log(savedUser?.name); // \"John Doe\"\n\n// Remove the item\nStorageUtils.removeLocalStorageItem('currentUser', window);\n\n// Session storage operations\nStorageUtils.setSessionStorageItem('tempData', &#123; value: 'temporary' &#125;, window);\nconst tempData = StorageUtils.getSessionStorageJsonItem('tempData', window);</code></pre>\n                </div>\n\n                <h3 id=\"clipboard-operations\">Clipboard Operations</h3>\n                <p class=\"content en\">Copy and paste text with clipboard API:</p>\n                <p class=\"content ko\">클립보드 API로 텍스트를 복사하고 붙여넣기하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; ClipBoardUtils &#125; from '@dooboostore/core-web/clipboard/ClipBoardUtils';\n\nasync function copyToClipboard(text: string) &#123;\n  try &#123;\n    await ClipBoardUtils.writeText(text, window);\n    console.log('Text copied successfully!');\n  &#125; catch (err) &#123;\n    console.error('Failed to copy text: ', err);\n  &#125;\n&#125;\n\nasync function readFromClipboard() &#123;\n  try &#123;\n    const text = await ClipBoardUtils.readText(window);\n    console.log('Clipboard content:', text);\n  &#125; catch (err) &#123;\n    console.error('Failed to read clipboard: ', err);\n  &#125;\n&#125;\n\ncopyToClipboard('Hello, world!');</code></pre>\n                </div>\n\n                <h3 id=\"element-loading\">Element Loading</h3>\n                <p class=\"content en\">Load images and audio elements asynchronously:</p>\n                <p class=\"content ko\">이미지와 오디오 요소를 비동기적으로 로드하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; ElementUtils &#125; from '@dooboostore/core-web/element/ElementUtils';\n\nasync function displayImage(src: string) &#123;\n  try &#123;\n    const imgElement = await ElementUtils.loadImage(src);\n    document.body.appendChild(imgElement);\n    console.log(`Image loaded: $&#123;imgElement.width&#125;x$&#123;imgElement.height&#125;`);\n  &#125; catch (error) &#123;\n    console.error('Failed to load image', error);\n  &#125;\n&#125;\n\nasync function loadAudio(src: string) &#123;\n  try &#123;\n    const audioElement = await ElementUtils.loadAudio(src);\n    audioElement.play();\n  &#125; catch (error) &#123;\n    console.error('Failed to load audio', error);\n  &#125;\n&#125;\n\ndisplayImage('https://via.placeholder.com/150');</code></pre>\n                </div>\n            </section>\n\n            <!-- Advanced Features -->\n            <section class=\"section\">\n                <h2 id=\"advanced-features\">Advanced Features</h2>\n                \n                <h3 id=\"image-conversion\">Image Conversion & Processing</h3>\n                <p class=\"content en\">Convert between different image formats and compress images:</p>\n                <p class=\"content ko\">다양한 이미지 형식 간 변환 및 이미지 압축:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; ConvertUtils &#125; from '@dooboostore/core-web/convert/ConvertUtils';\n\nasync function processImage(file: File) &#123;\n  try &#123;\n    // Convert File to ImageBitmap\n    const imageBitmap = await ConvertUtils.toImageBitmap(file);\n    \n    // Compress image\n    const compressedBlob = await ConvertUtils.compressImage(imageBitmap, &#123;\n      maxWidth: 800,\n      type: 'image/jpeg',\n      quality: 0.8\n    &#125;);\n    \n    // Convert to Base64\n    const base64 = await ConvertUtils.toBase64(compressedBlob, &#123;\n      type: 'image/jpeg',\n      quality: 0.8\n    &#125;);\n    \n    // Create object URL for display\n    const objectUrl = ConvertUtils.toObjectUrl(compressedBlob);\n    \n    console.log('Processed image:', &#123; base64, objectUrl &#125;);\n  &#125; catch (error) &#123;\n    console.error('Image processing failed:', error);\n  &#125;\n&#125;</code></pre>\n                </div>\n\n                <h3 id=\"script-loading\">Dynamic Script Loading</h3>\n                <p class=\"content en\">Load external scripts and stylesheets dynamically:</p>\n                <p class=\"content ko\">외부 스크립트와 스타일시트를 동적으로 로드하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; ScriptUtils &#125; from '@dooboostore/core-web/script/ScriptUtils';\n\nasync function loadExternalResources() &#123;\n  try &#123;\n    // Load external JavaScript\n    await ScriptUtils.loadScript(document, 'https://cdn.jsdelivr.net/npm/lodash@4.17.21/lodash.min.js');\n    \n    // Load external CSS\n    await ScriptUtils.loadStyleSheet(document, 'https://cdn.jsdelivr.net/npm/bootstrap@5.1.3/dist/css/bootstrap.min.css');\n    \n    // Load inline script\n    await ScriptUtils.loadScriptBody(document, `\n      console.log('Inline script loaded!');\n      window.myCustomFunction = function() &#123;\n        return 'Hello from dynamic script!';\n      &#125;;\n    `);\n    \n    console.log('All resources loaded successfully!');\n  &#125; catch (error) &#123;\n    console.error('Failed to load resources:', error);\n  &#125;\n&#125;</code></pre>\n                </div>\n\n                <h3 id=\"environment-detection\">Environment Detection</h3>\n                <p class=\"content en\">Detect browser environment and mobile webviews:</p>\n                <p class=\"content ko\">브라우저 환경과 모바일 웹뷰를 감지하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; ValidUtils &#125; from '@dooboostore/core-web/valid/ValidUtils';\n\nfunction checkEnvironment() &#123;\n  // Check if running in browser\n  if (ValidUtils.isBrowser()) &#123;\n    console.log('Running in browser environment');\n    \n    // Check for mobile\n    if (ValidUtils.isMobile()) &#123;\n      console.log('Mobile device detected');\n    &#125;\n    \n    // Check for social network in-app browsers\n    if (ValidUtils.isSocialNetworkServiceInappBrowser()) &#123;\n      console.log('Social network in-app browser detected');\n    &#125;\n    \n    // Check for iOS webview\n    if (ValidUtils.isWkWebview()) &#123;\n      console.log('iOS WKWebView detected');\n    &#125;\n    \n    // Check for Android webview\n    if (ValidUtils.isAndroidWebview()) &#123;\n      console.log('Android WebView detected');\n    &#125;\n    \n    // Check if has parent window (iframe)\n    if (ValidUtils.hasParentWindow(window)) &#123;\n      console.log('Running inside iframe');\n    &#125;\n  &#125; else &#123;\n    console.log('Not running in browser environment');\n  &#125;\n&#125;\n\ncheckEnvironment();</code></pre>\n                </div>\n\n                <h3 id=\"dom-manipulation\">DOM Manipulation</h3>\n                <p class=\"content en\">Advanced DOM querying and manipulation:</p>\n                <p class=\"content ko\">고급 DOM 쿼리 및 조작:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; ElementUtils &#125; from '@dooboostore/core-web/element/ElementUtils';\n\nfunction manipulateDOM() &#123;\n  // Query elements\n  const elements = ElementUtils.selectorElements('.my-class');\n  console.log(`Found $&#123;elements.length&#125; elements`);\n  \n  // Get element attributes as object\n  const firstElement = elements[0];\n  if (firstElement) &#123;\n    const attributes = ElementUtils.getAttributeToObject(firstElement);\n    console.log('Element attributes:', attributes);\n    \n    // Get element styles as object\n    if (firstElement instanceof HTMLElement) &#123;\n      const styles = ElementUtils.getStyleToObject(firstElement);\n      console.log('Element styles:', styles);\n    &#125;\n    \n    // Set multiple attributes\n    ElementUtils.setAttributeAttr(firstElement, [\n      &#123; name: 'data-processed', value: 'true' &#125;,\n      &#123; name: 'aria-label', value: 'Processed element' &#125;\n    ]);\n    \n    // Remove attributes\n    ElementUtils.removeAttribute(firstElement, ['data-temp', 'data-old']);\n  &#125;\n&#125;</code></pre>\n                </div>\n            </section>\n\n            <!-- API Reference -->\n            <section class=\"section\">\n                <h2 id=\"api-reference\">API Reference</h2>\n                \n                <h3 id=\"storage-api\">StorageUtils</h3>\n                <div class=\"api-grid\">\n                    <div class=\"api-item\">\n                        <h4>LocalStorage Methods</h4>\n                        <p class=\"content en\">Methods for localStorage operations</p>\n                        <p class=\"content ko\">localStorage 작업을 위한 메서드</p>\n                        <ul>\n                            <li><code>setLocalStorageItem(key: string, value: any, window: Window)</code></li>\n                            <li><code>getLocalStorageItem(key: string, window: Window): string | null</code></li>\n                            <li><code>getLocalStorageJsonItem&lt;T&gt;(key: string, window: Window): T | undefined</code></li>\n                            <li><code>removeLocalStorageItem(key: string, window: Window)</code></li>\n                            <li><code>cutLocalStorageItem(key: string, window: Window): string | null</code></li>\n                            <li><code>clearLocalStorage(window: Window)</code></li>\n                        </ul>\n                    </div>\n                    <div class=\"api-item\">\n                        <h4>SessionStorage Methods</h4>\n                        <p class=\"content en\">Methods for sessionStorage operations</p>\n                        <p class=\"content ko\">sessionStorage 작업을 위한 메서드</p>\n                        <ul>\n                            <li><code>setSessionStorageItem(key: string, value: any, window: Window)</code></li>\n                            <li><code>getSessionStorageItem(key: string, window: Window): string | null</code></li>\n                            <li><code>getSessionStorageJsonItem&lt;T&gt;(key: string, window: Window): T | undefined</code></li>\n                            <li><code>removeSessionStorageItem(key: string, window: Window)</code></li>\n                            <li><code>cutSessionStorageItem(key: string, window: Window): string | null</code></li>\n                            <li><code>clearSessionStorage(window: Window)</code></li>\n                        </ul>\n                    </div>\n                </div>\n\n                <h3 id=\"clipboard-api\">ClipBoardUtils</h3>\n                <div class=\"api-grid\">\n                    <div class=\"api-item\">\n                        <h4>Clipboard Operations</h4>\n                        <p class=\"content en\">Methods for clipboard API operations</p>\n                        <p class=\"content ko\">클립보드 API 작업을 위한 메서드</p>\n                        <ul>\n                            <li><code>readText(window: Window): Promise&lt;string&gt;</code></li>\n                            <li><code>writeText(data: string, window: Window): Promise&lt;void&gt;</code></li>\n                            <li><code>read(window: Window): Promise&lt;ClipboardItems&gt;</code></li>\n                            <li><code>write(data: ClipboardItems, clipboard?: Clipboard): Promise&lt;void&gt;</code></li>\n                        </ul>\n                    </div>\n                </div>\n\n                <h3 id=\"convert-api\">ConvertUtils</h3>\n                <div class=\"api-grid\">\n                    <div class=\"api-item\">\n                        <h4>Image Conversion</h4>\n                        <p class=\"content en\">Methods for image format conversion</p>\n                        <p class=\"content ko\">이미지 형식 변환을 위한 메서드</p>\n                        <ul>\n                            <li><code>toObjectUrl(data: File | Blob): string</code></li>\n                            <li><code>toBlob(source: ImageSource, config: ImageConvertConfig): Promise&lt;Blob&gt;</code></li>\n                            <li><code>toBase64(source: ImageSource, config: ImageConvertConfig): Promise&lt;string&gt;</code></li>\n                            <li><code>toImageBitmap(target: ImageSource): Promise&lt;ImageBitmap&gt;</code></li>\n                            <li><code>compressImage(img: ImageBitmap | File, config): Promise&lt;Blob | ImageBitmap&gt;</code></li>\n                        </ul>\n                    </div>\n                    <div class=\"api-item\">\n                        <h4>Image Processing</h4>\n                        <p class=\"content en\">Advanced image processing utilities</p>\n                        <p class=\"content ko\">고급 이미지 처리 유틸리티</p>\n                        <ul>\n                            <li><code>compressImageToBase64(img: ImageBitmap | File, config): Promise&lt;string&gt;</code></li>\n                            <li><code>toFile(source: ImageSource, config): Promise&lt;File&gt;</code></li>\n                            <li><code>toBlobURL(source: ImageSource, config): Promise&lt;string&gt;</code></li>\n                        </ul>\n                    </div>\n                </div>\n\n                <h3 id=\"element-api\">ElementUtils</h3>\n                <div class=\"api-grid\">\n                    <div class=\"api-item\">\n                        <h4>Resource Loading</h4>\n                        <p class=\"content en\">Methods for loading web resources</p>\n                        <p class=\"content ko\">웹 리소스 로딩을 위한 메서드</p>\n                        <ul>\n                            <li><code>loadImage(src: string): Promise&lt;HTMLImageElement&gt;</code></li>\n                            <li><code>loadAudio(src: string): Promise&lt;HTMLAudioElement&gt;</code></li>\n                        </ul>\n                    </div>\n                    <div class=\"api-item\">\n                        <h4>DOM Manipulation</h4>\n                        <p class=\"content en\">Methods for DOM element manipulation</p>\n                        <p class=\"content ko\">DOM 요소 조작을 위한 메서드</p>\n                        <ul>\n                            <li><code>querySelector(element: Element, selector: string): Element | null</code></li>\n                            <li><code>querySelectorAll(element: Element, selector: string): Element[]</code></li>\n                            <li><code>selectorElements(selector: string, element?: Element): Element[]</code></li>\n                            <li><code>getAttributeToObject(input: Element): any</code></li>\n                            <li><code>getStyleToObject(input: HTMLElement): any</code></li>\n                            <li><code>setAttributeAttr(result: Element, attrs: Attr[])</code></li>\n                        </ul>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Core Concepts -->\n            <section class=\"section\">\n                <h2 id=\"core-concepts\">Core Concepts</h2>\n                <div class=\"concepts-grid\">\n                    <div class=\"concept-item\">\n                        <h4>Browser API Wrappers</h4>\n                        <p class=\"content en\">Simplified interfaces for complex browser APIs like Clipboard and Storage</p>\n                        <p class=\"content ko\">클립보드와 스토리지 같은 복잡한 브라우저 API를 위한 단순화된 인터페이스</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Asynchronous Resource Loading</h4>\n                        <p class=\"content en\">Promise-based loading of images, audio, scripts, and stylesheets</p>\n                        <p class=\"content ko\">이미지, 오디오, 스크립트, 스타일시트의 Promise 기반 로딩</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Image Processing Pipeline</h4>\n                        <p class=\"content en\">Complete image conversion and compression workflow</p>\n                        <p class=\"content ko\">완전한 이미지 변환 및 압축 워크플로우</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Environment Detection</h4>\n                        <p class=\"content en\">Comprehensive browser and webview environment detection</p>\n                        <p class=\"content ko\">포괄적인 브라우저 및 웹뷰 환경 감지</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>DOM Utilities</h4>\n                        <p class=\"content en\">Enhanced DOM querying and manipulation with modern JavaScript</p>\n                        <p class=\"content ko\">현대적인 JavaScript를 사용한 향상된 DOM 쿼리 및 조작</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Cross-Platform Compatibility</h4>\n                        <p class=\"content en\">Consistent behavior across different browsers and mobile webviews</p>\n                        <p class=\"content ko\">다양한 브라우저와 모바일 웹뷰에서 일관된 동작</p>\n                    </div>\n                </div>\n            </section>\n        </div>\n    </div>\n</div>");

