/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = ("<div class=\"package-container\">\n    <div class=\"package-header\">\n        <div class=\"container\">\n            <h1>dom-render</h1>\n            <p class=\"content en\">HTML view template engine with DOM control and reactive rendering</p>\n            <p class=\"content ko\">DOM 제어와 반응형 렌더링을 지원하는 HTML 뷰 템플릿 엔진</p>\n            <div class=\"package-actions\">\n                <a href=\"https://github.com/dooboostore-develop/packages\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Github-555555?style=flat&logo=github&logoColor=white\" alt=\"GitHub\"/>\n                </a>\n                <a href=\"https://www.npmjs.com/package/@dooboostore/dom-render\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Npm-cc0000?style=flat&logo=npm&logoColor=white\" alt=\"NPM\"/>\n                </a>\n            </div>\n        </div>\n    </div>\n    <div class=\"package-content\">\n        <div class=\"container\">\n            <!-- Installation -->\n            <section class=\"section\">\n                <h2 id=\"installation\">Installation</h2>\n                <p class=\"content en\">Install the package and its dependencies:</p>\n                <p class=\"content ko\">패키지와 의존성을 설치하세요:</p>\n                \n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">npm</span>\n                    </div>\n                    <pre><code class=\"language-bash\">npm install @dooboostore/dom-render reflect-metadata</code></pre>\n                </div>\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">pnpm</span>\n                    </div>\n                    <pre><code class=\"language-bash\">pnpm add @dooboostore/dom-render reflect-metadata</code></pre>\n                </div>\n            </section>\n\n            <!-- Features -->\n            <section class=\"section\">\n                <h2 id=\"features\">Features</h2>\n                <div class=\"features-grid\">\n                    <div class=\"feature-item\">\n                        <h3>Template Engine</h3>\n                        <p class=\"content en\">Powerful HTML template engine with expression binding and control structures</p>\n                        <p class=\"content ko\">표현식 바인딩과 제어 구조를 지원하는 강력한 HTML 템플릿 엔진</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>DOM Control</h3>\n                        <p class=\"content en\">Direct DOM manipulation and reordering with efficient rendering</p>\n                        <p class=\"content ko\">효율적인 렌더링을 통한 직접적인 DOM 조작 및 재정렬</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Proxy-based Reactivity</h3>\n                        <p class=\"content en\">All internal variables managed by DomRenderProxy for automatic updates</p>\n                        <p class=\"content ko\">자동 업데이트를 위해 DomRenderProxy로 관리되는 모든 내부 변수</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Component System</h3>\n                        <p class=\"content en\">ComponentBase with decorators for attributes, queries, and events</p>\n                        <p class=\"content ko\">속성, 쿼리, 이벤트를 위한 데코레이터를 지원하는 ComponentBase</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Form Handling</h3>\n                        <p class=\"content en\">Built-in form binding with validation support</p>\n                        <p class=\"content ko\">검증 지원을 포함한 내장 폼 바인딩</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Routing System</h3>\n                        <p class=\"content en\">Declarative routing with path matching and parameters</p>\n                        <p class=\"content ko\">경로 매칭과 매개변수를 지원하는 선언적 라우팅</p>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Quick Start -->\n            <section class=\"section\">\n                <h2 id=\"quick-start\">Quick Start</h2>\n                \n                <h3 id=\"basic-usage\">Basic Usage</h3>\n                <p class=\"content en\">Get started with a simple template binding example:</p>\n                <p class=\"content ko\">간단한 템플릿 바인딩 예제로 시작하세요:</p>\n                \n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">TypeScript</span>\n                    </div>\n                    <pre><code class=\"language-typescript\">import { DomRender } from '@dooboostore/dom-render';\n\nclass AppData {\n  name: string = 'my name is dom-render';\n  color: string = '#ff0000';\n  \n  changeData() {\n    this.name = 'Updated name: ' + new Date().toLocaleTimeString();\n    this.color = '#' + Math.floor(Math.random()*16777215).toString(16);\n  }\n}\n\nconst data = new AppData();\nDomRender.run(data, document.querySelector('#app')!);</code></pre>\n                </div>\n\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">HTML</span>\n                    </div>\n                    <pre><code class=\"language-html\">&lt;!DOCTYPE html&gt;\n&lt;html lang=\"en\"&gt;\n&lt;head&gt;\n  &lt;meta charset=\"UTF-8\"&gt;\n  &lt;title&gt;DOM Render Example&lt;/title&gt;\n&lt;/head&gt;\n&lt;body id=\"app\"&gt;\n  &lt;h1 style=\"color: \\${this.color}\\$\"&gt;\\${this.name}\\$&lt;/h1&gt;\n  &lt;button dr-event-click=\"this.changeData()\"&gt;Change Data&lt;/button&gt;\n&lt;/body&gt;\n&lt;/html&gt;</code></pre>\n                </div>\n\n                <h3 id=\"expressions\">Template Expressions</h3>\n                <p class=\"content en\">Use different expression types for text and HTML content:</p>\n                <p class=\"content ko\">텍스트와 HTML 콘텐츠에 다양한 표현식 타입을 사용하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-html\">\n\n                        &lt;!-- HTML content (unescaped) --&gt;\n&lt;div&gt;&#35; &#123;this.htmlContent&#125;&#35;&lt;/div&gt;\n\n\n                        &lt;!-- Text content (escaped) --&gt;\n&lt;div&gt;\\&#36;&#123;this.name&#125;\\&#36;&lt;/div&gt;\n\n&lt;!-- Attribute binding --&gt;\n&lt;input type=\"text\" value=\"\\${this.inputValue}\\$\" style=\"\\${'color: ' + this.textColor}\\$\"&gt;</code></pre>\n                </div>\n\n                <h3 id=\"control-structures\">Control Structures</h3>\n                <p class=\"content en\">Use directives for conditional rendering and loops:</p>\n                <p class=\"content ko\">조건부 렌더링과 반복을 위한 디렉티브를 사용하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-html\">&lt;!-- Conditional rendering --&gt;\n&lt;div dr-if=\"this.isVisible\"&gt;This is visible&lt;/div&gt;\n&lt;div dr-if=\"this.user.role === 'admin'\"&gt;Admin content&lt;/div&gt;\n\n&lt;!-- Loop rendering --&gt;\n&lt;ul&gt;\n  &lt;li dr-for-of=\"this.items\"&gt;\\${&#35;it&#35;.name}\\$ - \\${&#35;it&#35;.price}\\$&lt;/li&gt;\n&lt;/ul&gt;\n\n&lt;!-- Traditional for loop --&gt;\n&lt;div dr-for=\"var i = 0; i &amp;lt; this.count; i++\"&gt;\n  Item \\${i + 1}\\$\n&lt;/div&gt;</code></pre>\n                </div>\n            </section>\n\n            <!-- Directives -->\n            <section class=\"section\">\n                <h2 id=\"directives\">Template Directives</h2>\n                <p class=\"content en\">DOM Render provides a comprehensive set of directives for template control:</p>\n                <p class=\"content ko\">DOM Render는 템플릿 제어를 위한 포괄적인 디렉티브 세트를 제공합니다:</p>\n                \n                <div class=\"directive-grid\">\n                    <div class=\"directive-item\">\n                        <h4>dr-if</h4>\n                        <p class=\"content en\">Conditional element rendering</p>\n                        <p class=\"content ko\">조건부 요소 렌더링</p>\n                    </div>\n                    <div class=\"directive-item\">\n                        <h4>dr-for / dr-for-of</h4>\n                        <p class=\"content en\">Loop rendering with iteration</p>\n                        <p class=\"content ko\">반복을 통한 루프 렌더링</p>\n                    </div>\n                    <div class=\"directive-item\">\n                        <h4>dr-event-*</h4>\n                        <p class=\"content en\">Event binding (click, input, change, etc.)</p>\n                        <p class=\"content ko\">이벤트 바인딩 (클릭, 입력, 변경 등)</p>\n                    </div>\n                    <div class=\"directive-item\">\n                        <h4>dr-value-link</h4>\n                        <p class=\"content en\">Two-way data binding for form inputs</p>\n                        <p class=\"content ko\">폼 입력을 위한 양방향 데이터 바인딩</p>\n                    </div>\n                    <div class=\"directive-item\">\n                        <h4>dr-class</h4>\n                        <p class=\"content en\">Dynamic CSS class binding</p>\n                        <p class=\"content ko\">동적 CSS 클래스 바인딩</p>\n                    </div>\n                    <div class=\"directive-item\">\n                        <h4>dr-style</h4>\n                        <p class=\"content en\">Dynamic inline style binding</p>\n                        <p class=\"content ko\">동적 인라인 스타일 바인딩</p>\n                    </div>\n                    <div class=\"directive-item\">\n                        <h4>dr-attr</h4>\n                        <p class=\"content en\">Dynamic attribute binding</p>\n                        <p class=\"content ko\">동적 속성 바인딩</p>\n                    </div>\n                    <div class=\"directive-item\">\n                        <h4>dr-this</h4>\n                        <p class=\"content en\">Context switching for nested objects</p>\n                        <p class=\"content ko\">중첩 객체를 위한 컨텍스트 전환</p>\n                    </div>\n                    <div class=\"directive-item\">\n                        <h4>dr-form</h4>\n                        <p class=\"content en\">Form data binding with validation</p>\n                        <p class=\"content ko\">검증을 포함한 폼 데이터 바인딩</p>\n                    </div>\n                    <div class=\"directive-item\">\n                        <h4>dr-checked / dr-disabled</h4>\n                        <p class=\"content en\">Boolean attribute binding</p>\n                        <p class=\"content ko\">불린 속성 바인딩</p>\n                    </div>\n                    <div class=\"directive-item\">\n                        <h4>dr-appender</h4>\n                        <p class=\"content en\">Dynamic list management</p>\n                        <p class=\"content ko\">동적 리스트 관리</p>\n                    </div>\n                    <div class=\"directive-item\">\n                        <h4>dr-route-match</h4>\n                        <p class=\"content en\">Route-based conditional rendering</p>\n                        <p class=\"content ko\">라우트 기반 조건부 렌더링</p>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Advanced Features -->\n            <section class=\"section\">\n                <h2 id=\"advanced-features\">Advanced Features</h2>\n                \n                <h3 id=\"component-system\">Component System</h3>\n                <p class=\"content en\">Create reusable components with ComponentBase and decorators:</p>\n                <p class=\"content ko\">ComponentBase와 데코레이터로 재사용 가능한 컴포넌트를 생성하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import { ComponentBase, attribute, query, event } from '@dooboostore/dom-render';\n\nexport class UserCard extends ComponentBase&lt;{ 'user-name': string, 'user-email': string }&gt; {\n    @attribute\n    userName: string = 'Default User';\n\n    @attribute({ name: 'user-email' })\n    userEmail: string = '';\n\n    @query('button.edit')\n    private editButton: HTMLButtonElement;\n\n    @query('span.status')\n    private statusElements: HTMLSpanElement[];\n\n    @event({ query: 'button.edit', name: 'click' })\n    onEditClick(e: MouseEvent) {\n        console.log('Edit clicked for:', this.userName);\n    }\n\n    onInitRender() {\n        if (this.editButton) {\n            this.editButton.style.display = this.userEmail ? 'block' : 'none';\n        }\n    }\n}</code></pre>\n                </div>\n\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">Usage in HTML</span>\n                    </div>\n                    <pre><code class=\"language-html\">&lt;user-card user-name=\"John Doe\" user-email=\"john@example.com\"&gt;\n  &lt;div&gt;\n    &lt;h3&gt;\\${@this@.userName}\\$&lt;/h3&gt;\n    &lt;p&gt;\\${@this@.userEmail}\\$&lt;/p&gt;\n    &lt;span class=\"status\"&gt;Active&lt;/span&gt;\n    &lt;button class=\"edit\"&gt;Edit User&lt;/button&gt;\n  &lt;/div&gt;\n&lt;/user-card&gt;</code></pre>\n                </div>\n\n                <h3 id=\"form-handling\">Form Handling & Validation</h3>\n                <p class=\"content en\">Handle forms with built-in validation support:</p>\n                <p class=\"content ko\">내장 검증 지원으로 폼을 처리하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import { DomRender } from '@dooboostore/dom-render';\nimport { FormValidator, NotEmptyValidator, RegExpTestValidator } from '@dooboostore/dom-render/validator';\n\nclass UserForm {\n    form: FormValidator = new FormValidator();\n\n    constructor() {\n        this.form.name = new NotEmptyValidator();\n        this.form.email = new RegExpTestValidator(/^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/);\n        this.form.age = new NotEmptyValidator();\n    }\n\n    submit() {\n        if (this.form.valid()) {\n            console.log('Form is valid:', this.form);\n            // Process form data\n        } else {\n            console.log('Form has errors');\n            // Show validation errors\n        }\n    }\n}</code></pre>\n                </div>\n\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">Form HTML</span>\n                    </div>\n                    <pre><code class=\"language-html\">&lt;form dr-form=\"@this@.form\" dr-event-submit=\"@this@.submit(); $event.preventDefault();\"&gt;\n  &lt;div&gt;\n    &lt;label&gt;Name:&lt;/label&gt;\n    &lt;input name=\"name\" type=\"text\" required&gt;\n  &lt;/div&gt;\n  &lt;div&gt;\n    &lt;label&gt;Email:&lt;/label&gt;\n    &lt;input name=\"email\" type=\"email\" required&gt;\n  &lt;/div&gt;\n  &lt;div&gt;\n    &lt;label&gt;Age:&lt;/label&gt;\n    &lt;input name=\"age\" type=\"number\" required&gt;\n  &lt;/div&gt;\n  &lt;button type=\"submit\"&gt;Submit&lt;/button&gt;\n&lt;/form&gt;</code></pre>\n                </div>\n\n                <h3 id=\"routing\">Routing System</h3>\n                <p class=\"content en\">Implement client-side routing with declarative components:</p>\n                <p class=\"content ko\">선언적 컴포넌트로 클라이언트 사이드 라우팅을 구현하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import { DomRender, DomRenderRunConfig } from '@dooboostore/dom-render';\n\nclass App {\n    currentPath: string = '/';\n    \n    constructor() {\n        // Router will automatically update currentPath\n    }\n}\n\nconst config: DomRenderRunConfig&lt;App&gt; = {\n    window: window,\n    routerType: 'path' // or 'hash'\n};\n\nconst domRender = new DomRender({\n    rootObject: new App(),\n    target: document.querySelector('#app')!,\n    config: config\n}, { autoGo: '/' });</code></pre>\n                </div>\n\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">Routing HTML</span>\n                    </div>\n                    <pre><code class=\"language-html\">&lt;nav&gt;\n  &lt;button dr-event-click=\"$router?.go({path:'/'})\"&gt;Home&lt;/button&gt;\n  &lt;button dr-event-click=\"$router?.go({path:'/about'})\"&gt;About&lt;/button&gt;\n  &lt;button dr-event-click=\"$router?.go({path:'/user/123'})\"&gt;User 123&lt;/button&gt;\n&lt;/nav&gt;\n\n&lt;main&gt;\n  &lt;dr-route-match value=\"/\"&gt;\n    &lt;h1&gt;Home Page&lt;/h1&gt;\n  &lt;/dr-route-match&gt;\n\n  &lt;dr-route-match value=\"/about\"&gt;\n    &lt;h1&gt;About Page&lt;/h1&gt;\n  &lt;/dr-route-match&gt;\n\n  &lt;dr-route-match value=\"/user/{id:[0-9]+}\"&gt;\n    &lt;h1&gt;User Profile&lt;/h1&gt;\n    &lt;p&gt;User ID: \\${$router.pathData?.id}\\$&lt;/p&gt;\n  &lt;/dr-route-match&gt;\n&lt;/main&gt;</code></pre>\n                </div>\n            </section>\n\n            <!-- Core Concepts -->\n            <section class=\"section\">\n                <h2 id=\"core-concepts\">Core Concepts</h2>\n                <div class=\"concepts-grid\">\n                    <div class=\"concept-item\">\n                        <h4>DomRender</h4>\n                        <p class=\"content en\">Main class for initializing and managing template rendering</p>\n                        <p class=\"content ko\">템플릿 렌더링을 초기화하고 관리하는 메인 클래스</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>DomRenderProxy</h4>\n                        <p class=\"content en\">Proxy system for automatic change detection and DOM updates</p>\n                        <p class=\"content ko\">자동 변경 감지와 DOM 업데이트를 위한 프록시 시스템</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>ComponentBase</h4>\n                        <p class=\"content en\">Base class for creating reusable components with lifecycle hooks</p>\n                        <p class=\"content ko\">생명주기 훅을 포함한 재사용 가능한 컴포넌트 생성을 위한 기본 클래스</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Template Directives</h4>\n                        <p class=\"content en\">Special attributes (dr-*) for controlling DOM behavior</p>\n                        <p class=\"content ko\">DOM 동작을 제어하는 특수 속성 (dr-*)</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Expression Binding</h4>\n                        <p class=\"content en\">\\${}$ and &#35;{}&#35; syntax for data binding in templates</p>\n                        <p class=\"content ko\">템플릿에서 데이터 바인딩을 위한 \\${}$와 &#35;{}&#35; 구문</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Form Validation</h4>\n                        <p class=\"content en\">Built-in validators for form data validation</p>\n                        <p class=\"content ko\">폼 데이터 검증을 위한 내장 검증기</p>\n                    </div>\n                </div>\n            </section>\n        </div>\n    </div>\n</div>");

